class Solution:
    def invalidTransactions(self, transactions):
        parsed = []
        for t in transactions:
            name, time, amount, city = t.split(',')
            parsed.append((name, int(time), int(amount), city, t))
        bad = [False] * len(parsed)
        for i in range(len(parsed)):
            if parsed[i][2] > 1000:
                bad[i] = True
            for j in range(len(parsed)):
                if i == j:
                    continue
                ni, ti, _, ci, _ = parsed[i]
                nj, tj, _, cj, _ = parsed[j]
                if ni == nj and ci != cj and abs(ti - tj) <= 60:
                    bad[i] = True
        return [parsed[i][4] for i in range(len(parsed)) if bad[i]]

