class Solution:
    def invalidTransactions(self, transactions):
        from collections import defaultdict
        recs = []
        by_name = defaultdict(list)
        for idx, t in enumerate(transactions):
            name, time, amount, city = t.split(',')
            recs.append((name, int(time), int(amount), city))
            by_name[name].append(idx)
        invalid = set()
        for idx, (name, time, amount, city) in enumerate(recs):
            if amount > 1000:
                invalid.add(idx)
            for jdx in by_name[name]:
                if jdx == idx:
                    continue
                _, tj, _, cj = recs[jdx]
                if cj != city and abs(tj - time) <= 60:
                    invalid.add(idx)
                    invalid.add(jdx)
        return [transactions[i] for i in sorted(invalid)]

