var invalidTransactions = function(transactions) {
    const recs = transactions.map(t => {
        const [name, time, amount, city] = t.split(',');
        return { name, time: +time, amount: +amount, city };
    });
    const byName = new Map();
    recs.forEach((r, i) => {
        if (!byName.has(r.name)) byName.set(r.name, []);
        byName.get(r.name).push(i);
    });
    const invalid = new Set();
    recs.forEach((r, i) => {
        if (r.amount > 1000) invalid.add(i);
        for (const j of byName.get(r.name)) {
            if (j === i) continue;
            const o = recs[j];
            if (o.city !== r.city && Math.abs(o.time - r.time) <= 60) {
                invalid.add(i);
                invalid.add(j);
            }
        }
    });
    const idxs = [...invalid].sort((a, b) => a - b);
    return idxs.map(i => transactions[i]);
};
